#nullable enable // autogenerated

using MVZ2Logic;
using MVZ2Logic.Definitions;
using MVZ2Logic.Options;
using MVZ2Logic.Saves;
using UnityEngine;

namespace MVZ2.GameContent.Options
{
    [AutoOptionWidgetDefinition(LogicOptionWidgetNames.hpBarsHoverDisplayRange)]
    public class HPBarsHoverDisplayRangeOptionSlider : OptionSliderDefinition
    {
        public HPBarsHoverDisplayRangeOptionSlider(string nsp, string name) : base(nsp, name)
        {
        }
        public override bool ShouldEnable(IOptionContext context)
        {
            return Global.Saves.IsHPBarUnlocked() || Global.Debugs.CanUseDebugFeatures();
        }

        public override float GetValue(IOptionContext context)
        {
            return Global.Options.GetHPBarHoverDisplayRange();
        }

        public override string GetLabelValue(IOptionContext context, float value)
        {
            return Mathf.RoundToInt(value).ToString();
        }

        public override void OnValueChanged(IOptionContext context, float value)
        {
            Global.Options.SetHPBarHoverDisplayRange(value);
        }

        public override void OnEndEdit(IOptionContext context, float value)
        {
            Global.Options.SetHPBarHoverDisplayRange(value);
            Global.Options.SaveOptions();
        }
    }
}
